body.raw:
{
  "email": "testtenant@example.com",
  "password": "123456"
}

{
  "display_name": "My Salon",
  "tz": "Asia/Kolkata",
  "date_format": "DD-MM-YYYY",
  "currency": "INR",
  "address": "123 Main St, Chennai",
  "owner_phone_number": { "code": "+91", "number": "9876543210" }
}

{
  "templates": {
    "wa_booking_confirmed": "✅ Hi {{name}}, your appointment is confirmed for {{date}} at {{time}}. Reply *hi* to return to the menu.",
    "wa_booking_reminder": "⏰ Reminder: Your appointment is tomorrow at {{time}}. See you soon!",
    "wa_type_menu_hint": "Type *hi* or *menu* to see what we can help you with."
  }
}

{
  "menu_id": "welcome_message",
  "name": "Main Menu",
  "tree": {
    "root": "main",
    "nodes": [
      {
        "id": "main",
        "type": "submenu",
        "title": "Welcome! How can we help?",
        "prompt": "Reply with a number:",
        "options": [
          { "key": "1", "label": "Book Appointment",  "next": "workflow.demo_booking_flow" },
          { "key": "2", "label": "Quick Booking",     "next": "workflow.demo_quick_booking_flow" },
          { "key": "3", "label": "Services & Prices", "next": "workflow.demo_price_list_flow" },
          { "key": "4", "label": "Contact Us",        "next": "contact_info" }
        ]
      },
      {
        "id": "contact_info",
        "type": "action",
        "action_type": "static_text",
        "text": "📞 Call us: +91 98765 00001\n📧 admin@demo.com\n\nWe reply within 1 hour!"
      }
    ]
  }
}

{
  "phone": "+919876543210",
  "body": "workflow.demo_booking_flow",
  "tenant": "{{tenant}}"
}

{
  "phone": "+919876543210",
  "body": "price",
  "tenant": "{{tenant}}"
}

{
  "new_time": "11:00",
  "new_date": "{{date_str}}"
}

{
  "phone": "+919876543210",
  "name": "Kavitha Rajan",
  "email": "kavitha@demo.com",
  "tags": ["vip", "regular"]
}

{
  "items": [
    { "sku": "SKU-DEMO-1", "qty": 2 }
  ],
  "customer_phone": "+919876543210"
}

{
  "title": "Summer Sale",
  "description": "20% off selected skincare products this summer!",
  "valid_from": "2026-04-01T00:00:00",
  "valid_until": "2026-06-30T23:59:59",
  "product_skus": ["SKU-DEMO-1", "SKU-DEMO-2"],
  "discount_info": {
    "type": "percent",
    "value": 20
  },
  "active": true
}

{
  "title": "Flat 50 Off",
  "description": "Get flat ₹50 off on all electronics.",
  "valid_from": "2026-04-01T00:00:00",
  "valid_until": "2026-12-31T23:59:59",
  "product_skus": ["SKU-DEMO-3"],
  "discount_info": {
    "type": "amount",
    "value": 50
  },
  "active": true
}

{
  "description": "Extended until end of year!",
  "valid_until": "2026-12-31T23:59:59",
  "discount_info": {
    "type": "percent",
    "value": 25
  }
}

{
  "name": "Season Sale – WhatsApp + Email",
  "channel": "both",
  "message": "🌟 Season Sale is LIVE!\n\nGet 20% OFF on selected services this weekend. Tap below to book your slot.",
  "interactive_type": "cta_url",
  "cta_entries": [
    { "id": "cta_1", "display_text": "Book Now", "url": "https://example.com/book" }
  ],
  "cta_append_urls_to_body": true,
  "offer_code": "SEASON20",
  "audience": { "type": "all" }
}

{
  "name": "Flash Deal – SMS Only",
  "channel": "sms",
  "message": "Demo Salon: Flash deal today only! Any service above Rs.500 at 10% OFF. Code: FLASH10. Valid till 8 PM.",
  "attachments": [
    { "type": "link", "url": "https://example.com/book", "name": "Book Online" }
  ],
  "offer_code": "FLASH10",
  "audience": { "type": "all" }
}

{
  "name": "VIP Loyalty Reward – SMS + WA",
  "channel": "sms+whatsapp",
  "message": "🌟 You're a VIP customer! Enjoy a complimentary service on your next visit. Show this message at the counter. Valid this month only.",
  "offer_code": "VIP2026",
  "audience": { "type": "tags", "tags": ["vip"] }
}

{
  "name": "Annual Day Promotion – All Channels",
  "channel": "all",
  "message": "🎉 Annual celebration sale — 25% off everything this week. Use code ANNUAL25.",
  "offer_code": "ANNUAL25",
  "audience": { "type": "all" }
}

{
  "message": "Updated promotion message copy",
  "offer_code": "UPDATED10"
}

{
  "tenant": "{{tenant}}",
  "workflow_id": "demo_quick_booking_flow",
  "name": "Quick Booking (Auto-Slot)",
  "description": "Fastest booking: choose service — date and time auto-assigned to next available slot.",
  "active": true,
  "requires_caps": ["appointments"],
  "steps": [
    { "action_code": "SHOW_SERVICES",   "label": "Pick a service — we'll find the next available slot:", "input_required": true,  "ui_type": "list", "params": {} },
    { "action_code": "CONFIRM_BOOKING", "label": "Confirm your appointment",                              "input_required": false, "ui_type": "list", "params": {} },
    { "action_code": "END",             "label": "✅ Done! Your next available slot is booked. Reply *hi* anytime.",             "input_required": false, "ui_type": "list", "params": {} }
  ]
}

{
  "tenant": "{{tenant}}",
  "workflow_id": "demo_price_list_flow",
  "name": "Services & Price List",
  "description": "Live price list from tenant services catalog (read-only).",
  "active": true,
  "requires_caps": ["appointments"],
  "steps": [
    { "action_code": "SHOW_SERVICE_PRICES", "label": "💇 Our services & prices:", "input_required": false, "ui_type": "list", "params": {} },
    { "action_code": "END", "label": "Reply *hi* for the main menu or *book* to schedule.", "input_required": false, "ui_type": "list", "params": {} }
  ]
}

{
  "tenant": "{{tenant}}",
  "workflow_id": "store_browse_flow",
  "name": "Store Product Browse",
  "active": true,
  "requires_caps": ["store"],
  "steps": [
    { "action_code": "BROWSE_CATALOG", "label": "Browse our products:", "input_required": false, "ui_type": "list", "params": {} },
    { "action_code": "CHECK_PRODUCT",  "label": "Type a product name for details:", "input_required": true,  "ui_type": "text", "params": {} },
    { "action_code": "END",            "label": "✅ Thanks for browsing! Reply *hi* for the main menu.", "input_required": false, "ui_type": "list", "params": {} }
  ]
}

{
  "tenant": "{{tenant}}",
  "workflow_id": "store_support_flow",
  "name": "Order Support & Returns",
  "active": true,
  "requires_caps": ["store"],
  "steps": [
    { "action_code": "TRACK_ORDER", "label": "Please share your Order ID (e.g. ORD-XXXX):", "input_required": true,  "ui_type": "text", "params": {} },
    { "action_code": "END",         "label": "Reply *hi* anytime for the main menu.", "input_required": false, "ui_type": "list", "params": {} }
  ]
}

{
  "tenant": "{{tenant}}",
  "workflow_id": "free_text_inquiry_flow",
  "name": "Free Text Inquiry",
  "description": "Collect a free-text message from the customer and route to AI or support.",
  "active": true,
  "requires_caps": [],
  "steps": [
    { "action_code": "AI_FREE_TEXT",  "label": "Send us your question or message:", "input_required": true,  "ui_type": "text", "params": {} },
    { "action_code": "END",           "label": "Thanks! Our team will get back to you shortly. Reply *hi* for the main menu.", "input_required": false, "ui_type": "text", "params": {} }
  ]
}
